module top_module(
    input [3:0] A,
    input [3:0] B,
    input [1:0] OP,
    output [3:0] RESULT
);parameter NUM_OPERATIONS = 4;

reg [3:0] obf_result;

always @(*) begin
    case (OP)
        2'b00: obf_result = A + B;
        2'b01: obf_result = A - B;
        2'b10: obf_result = A * B;
        2'b11: obf_result = A / B;
    endcase
end

assign RESULT = obf_result;

endmodule
